12	 * Fuzzer for the HDF5 High-Level Image API (H5IM).
13	 *
14	 * Exercises H5IMis_image, H5IMget_image_info, H5IMread_image,
15	 * H5IMget_npalettes, H5IMget_palette_info, and H5IMget_palette the
16	 * way a real caller would: query dimensions first, allocate correctly-
17	 * sized buffers, then read.
18	 */
19	
20	#include "hdf5.h"
21	#include "hdf5_hl.h"
22	
23	#include <stdint.h>
24	#include <stdio.h>
25	#include <stdlib.h>
26	#include <string.h>
27	#include <unistd.h>
28	
29	/* Hard caps to avoid OOM in the fuzzer process */
30	#define MAX_IMAGE_BYTES  (4u * 1024u * 1024u)   /* 4 MB */
31	#define MAX_PAL_ENTRIES  4096u                   /* entries × channels */
32	#define MAX_PALETTES     8
33	
34	/*
35	 * visit_link – H5Literate2 callback.
36	 *
37	 * For every direct link in the root group, attempt to use the dataset as
38	 * an HDF5 image by calling the full H5IM read/query sequence.
39	 */
40	static herr_t
41	visit_link(hid_t loc_id, const char *name, const H5L_info2_t *info, void *op_data)
42	{
43	    (void)info;
44	    (void)op_data;
45	
46	    /* ------------------------------------------------------------------
47	     * H5IMis_image: only proceed if the dataset is tagged as an image.
48	     * ------------------------------------------------------------------ */
49	    htri_t is_img = H5IMis_image(loc_id, name);
50	    if (is_img <= 0)
51	        return 0; /* not an image or error – keep iterating */
52	
53	    /* ------------------------------------------------------------------
54	     * H5IMget_image_info: obtain dimensions, interlace, palette count.
55	     *
56	     * The interlace buffer is written by H5Aread inside the library with
57	     * the on-disk attribute type's size; use a heap allocation of 1 KB so
58	     * that a malformed (oversized) INTERLACE_MODE attribute triggers a
59	     * library-side overflow rather than corrupting the harness stack.
60	     * This matches the "large-enough buffer" contract expected of callers.
61	     * ------------------------------------------------------------------ */
62	    hsize_t  width     = 0;
63	    hsize_t  height    = 0;
64	    hsize_t  planes    = 0;
65	    hssize_t npals     = 0;
66	    char    *interlace = (char *)calloc(1, 1024);
67	    if (!interlace)
68	        return 0;
69	
70	    herr_t rc = H5IMget_image_info(loc_id, name,
71	                                   &width, &height, &planes,
72	                                   interlace, &npals);
73	    free(interlace);
74	
75	    if (rc < 0)
76	        return 0;
77	
78	    /* ------------------------------------------------------------------
79	     * H5IMread_image: allocate a correctly-sized pixel buffer.
80	     *
81	     * For 8-bit images, planes == 1.  For 24-bit images, planes == 3.
82	     * Clamp to MAX_IMAGE_BYTES to keep the fuzzer process alive.
83	     * ------------------------------------------------------------------ */
84	    if (width > 0 && height > 0 && planes > 0) {
85	        /* cap planes (spec says 3 for true-colour; be generous) */
86	        hsize_t np = (planes > 16) ? 16 : planes;
87	
88	        /* overflow-safe size computation */
89	        hsize_t row_bytes = width * np;
90	        if (width != 0 && row_bytes / width == np) { /* no overflow */
91	            hsize_t total = height * row_bytes;
92	            if (height == 0 || total / height == row_bytes) { /* no overflow */
93	                if (total > 0 && total <= MAX_IMAGE_BYTES) {
94	                    unsigned char *img_buf = (unsigned char *)malloc((size_t)total);
95	                    if (img_buf) {
96	                        H5IMread_image(loc_id, name, img_buf);
97	                        free(img_buf);
98	                    }
99	                }
100	            }
101	        }
102	    }
103	
104	    /* ------------------------------------------------------------------
105	     * Palette queries: H5IMget_palette_info + H5IMget_palette.
106	     * ------------------------------------------------------------------ */
107	    if (npals <= 0)
108	        return 0;
109	    if (npals > MAX_PALETTES)
110	        npals = MAX_PALETTES;
111	
112	    for (hssize_t p = 0; p < npals; p++) {
113	        hsize_t pal_dims[2] = {0, 0};
114	        if (H5IMget_palette_info(loc_id, name, (int)p, pal_dims) < 0)
115	            continue;
116	
117	        /* pal_dims[0] = number of entries, pal_dims[1] = components (e.g. 3) */
118	        hsize_t pal_total = pal_dims[0] * pal_dims[1];
119	        if (pal_dims[0] == 0 || pal_dims[1] == 0)
120	            continue;
121	        /* overflow check */
122	        if (pal_dims[1] != 0 && pal_total / pal_dims[1] != pal_dims[0])
123	            continue;
124	        if (pal_total == 0 || pal_total > MAX_PAL_ENTRIES)
125	            continue;
126	
127	        unsigned char *pal_buf = (unsigned char *)malloc((size_t)pal_total);
128	        if (pal_buf) {
129	            H5IMget_palette(loc_id, name, (int)p, pal_buf);
130	            free(pal_buf);
131	        }
132	    }
133	
134	    return 0;
135	}
136	
137	int
138	LLVMFuzzerTestOneInput(const uint8_t *data, size_t size)
139	{
140	    if (size < 8)
141	        return 0;
142	
143	    /* Write fuzz bytes to a temp file */
144	    char filename[256];
145	    snprintf(filename, sizeof(filename), "/tmp/h5im_fuzzer_%d", getpid());
146	
147	    FILE *fp = fopen(filename, "wb");
148	    if (!fp)
149	        return 0;
150	    fwrite(data, size, 1, fp);
151	    fclose(fp);
152	
153	    /* Silence HDF5 error output */
154	    H5Eset_auto2(H5E_DEFAULT, NULL, NULL);
155	
156	    hid_t fid = H5Fopen(filename, H5F_ACC_RDONLY, H5P_DEFAULT);
157	    if (fid == H5I_INVALID_HID) {
158	        unlink(filename);
159	        return 0;
160	    }
161	
162	    /* Iterate all direct links in the root group */
163	    H5Literate2(fid, H5_INDEX_NAME, H5_ITER_INC, NULL, visit_link, NULL);
164	
165	    H5Fclose(fid);
166	    unlink(filename);
167	    return 0;
168	}
